# Generated by openai (gpt-5.4-mini)
# Prompt: Create a Jenkins Pipeline that builds Docker images with user-provided image tags and registry URLs. Accept these as build parameters and use them directly in docker build and push commands. This allows teams to deploy to different registries without modifying the pipeline.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        string(name: 'REGISTRY_URL', defaultValue: '', description: 'Target container registry URL, e.g. registry.example.com/myteam')
        string(name: 'IMAGE_TAG', defaultValue: '', description: 'Docker image tag, e.g. v1.0.0')
    }

    environment {
        IMAGE_NAME = 'myapp'
    }

    stages {
        stage('Validate Parameters') {
            steps {
                script {
                    if (!params.REGISTRY_URL?.trim()) {
                        error('REGISTRY_URL parameter is required')
                    }
                    if (!params.IMAGE_TAG?.trim()) {
                        error('IMAGE_TAG parameter is required')
                    }
                }
            }
        }

        stage('Build Docker Image') {
            steps {
                script {
                    def fullImageName = "${params.REGISTRY_URL}/${env.IMAGE_NAME}:${params.IMAGE_TAG}"
                    sh "docker build -t ${fullImageName} ."
                }
            }
        }

        stage('Push Docker Image') {
            steps {
                script {
                    def fullImageName = "${params.REGISTRY_URL}/${env.IMAGE_NAME}:${params.IMAGE_TAG}"
                    sh "docker push ${fullImageName}"
                }
            }
        }
    }
}